export function getNetIQEnv(location: string) {
  if (location === undefined)
    throw new Error(`No redirection location provided.`);

  const locationTokens = location.replace('https://', '').split('/');

  if (locationTokens.length < 3)
    throw new Error(`Unexpected redirection format: ${location}.`);

  let netIQEnv = locationTokens[0];

  if (['idp.renault.com', 'idp2.renault.com'].indexOf(netIQEnv) == -1)
    throw new Error(`Unexpected NetIQ environment '${netIQEnv}'.`);

  return netIQEnv;
}
